<style>
.iday-slider {
  position: relative;
  overflow: hidden;
  max-width: 100%;
  user-select: none;
  touch-action: pan-y;
}

.iday-slides {
  display: flex;
  transition: transform 0.6s ease;
}

.iday-slide {
  min-width: 100%;
  box-sizing: border-box;
}

.iday-slide img {
  width: 100%;
  height: auto;
  max-width: 100%; /* ⬅️ Penting: cegah stretch */
  display: block;
  object-fit: contain; /* ⬅️ Jaga rasio asli, jangan crop */
  object-position: center;
}

/* Controls (Arrow only, no background) */
.iday-prev, .iday-next {
  position: absolute;
  top: 50%;
  transform: translateY(-50%);
  width: 30px;
  height: 30px;
  cursor: pointer;
  z-index: 10;
}

.iday-prev::before, .iday-next::before {
  content: '';
  display: block;
  width: 12px;
  height: 12px;
  border-top: 2px solid rgba(255,255,255,0.7);
  border-right: 2px solid rgba(255,255,255,0.7);
  margin: auto;
  position: relative;
  top: 8px;
  transition: border-color 0.3s ease;
}

.iday-prev::before {
  transform: rotate(-135deg);
  left: 8px;
}

.iday-next::before {
  transform: rotate(45deg);
  left: 10px;
}

.iday-prev:hover::before, .iday-next:hover::before {
  border-color: rgba(255,255,255,1);
}

.iday-prev { left: 10px; }
.iday-next { right: 10px; }

/* Bullets */
.iday-dots {
  position: absolute;
  bottom: 15px;
  width: 100%;
  text-align: center;
  z-index: 9;
}

.iday-dots .iday-dot {
  display: inline-block;
  width: 10px;
  height: 10px;
  margin: 0 4px;
  border-radius: 50%;
  background-color: rgba(255,255,255,0.4);
  transition: background-color 0.3s ease;
}

.iday-dots .iday-dot.active {
  background-color: rgba(255,255,255,0.9);
}
</style>

<script>
(function(){
  const slider = document.querySelector('.iday-slider');
  const slides = slider.querySelector('.iday-slides');
  const slideItems = slider.querySelectorAll('.iday-slide');
  const prevBtn = slider.querySelector('.iday-prev');
  const nextBtn = slider.querySelector('.iday-next');
  const dotsContainer = slider.querySelector('.iday-dots');
  let index = 0;
  let autoPlay;
  const interval = 7000;

  // Create dots
  slideItems.forEach((_, i) => {
    const dot = document.createElement('span');
    dot.classList.add('iday-dot');
    if(i===0) dot.classList.add('active');
    dot.addEventListener('click', () => goToSlide(i));
    dotsContainer.appendChild(dot);
  });
  const dots = dotsContainer.querySelectorAll('.iday-dot');

  function goToSlide(i){
    index = i;
    slides.style.transform = `translateX(-${i*100}%)`;
    dots.forEach(dot => dot.classList.remove('active'));
    dots[i].classList.add('active');
  }

  function nextSlide(){
    index = (index+1) % slideItems.length;
    goToSlide(index);
  }

  function prevSlide(){
    index = (index-1+slideItems.length) % slideItems.length;
    goToSlide(index);
  }

  nextBtn.addEventListener('click', nextSlide);
  prevBtn.addEventListener('click', prevSlide);

  // Autoplay
  function startAutoPlay(){
    autoPlay = setInterval(nextSlide, interval);
  }
  function stopAutoPlay(){
    clearInterval(autoPlay);
  }
  slider.addEventListener('mouseenter', stopAutoPlay);
  slider.addEventListener('mouseleave', startAutoPlay);

  startAutoPlay();

  // Swipe/Drag Support
  let startX = 0;
  let isDown = false;

  // Mouse drag
  slider.addEventListener('mousedown', e => {
    isDown = true;
    startX = e.pageX;
  });
  slider.addEventListener('mouseup', e => {
    if(!isDown) return;
    let diff = e.pageX - startX;
    if(diff > 50) prevSlide();
    if(diff < -50) nextSlide();
    isDown = false;
  });
  slider.addEventListener('mouseleave', () => { isDown = false; });

  // Touch swipe (Mobile)
  slider.addEventListener('touchstart', e => {
    startX = e.touches[0].clientX;
  });
  slider.addEventListener('touchend', e => {
    let diff = e.changedTouches[0].clientX - startX;
    if(diff > 50) prevSlide();
    if(diff < -50) nextSlide();
  });
})();
</script>				</div>
